// TypeScript implementation for Optional Readonly Fields
interface OptionalReadonlyFieldsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processOptionalReadonlyFields(item: OptionalReadonlyFieldsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processOptionalReadonlyFields({ id: 1, title: 'Optional Readonly Fields', status: 'active' }));

